/**
 * Deterministic FNV-1a hash (no crypto dependency)
 * @param {*} value - any JSON-serializable value
 * @returns {string} 8-character hex hash
 */
export function hash(value) {
  const str = JSON.stringify(
    value,
    Object.keys(value instanceof Object ? value : {}).sort()
  );
  let h = 2166136261n;
  for (let i = 0; i < str.length; i++) {
    h ^= BigInt(str.charCodeAt(i));
    h = BigInt.asUintN(32, h * 16777619n);
  }
  return h.toString(16).padStart(8, '0');
}

/**
 * Compute Merkle root of hash sequence
 * Used to verify integrity of entire history in O(log n)
 * @param {Array<string>} hashes - array of hash strings
 * @returns {string} Merkle root hash
 */
export function merkleRoot(hashes) {
  if (!hashes.length) return '0'.repeat(8);
  let layer = [...hashes];
  while (layer.length > 1) {
    const next = [];
    for (let i = 0; i < layer.length; i += 2) {
      next.push(hash({ l: layer[i], r: layer[i + 1] ?? layer[i] }));
    }
    layer = next;
  }
  return layer[0];
}